#include <stdio.h>
#include <string.h>
int minOperations(char *S) {
    int n = strlen(S);
    int dp[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = n - 1; i >= 0; i--) {
        for (int j = i; j < n; j++) {
            if (i == j) {
                dp[i][j] = 0;
            } else if (S[i] == S[j]) {
                dp[i][j] = dp[i + 1][j - 1];
            } else {
                dp[i][j] = 1 + min(dp[i + 1][j], dp[i][j - 1]);
            }
        }
    }
    return dp[0][n - 1];
}
int main() {
    char S[100001];
    scanf("%s", S);
    printf("%d\n", minOperations(S));
    return 0;
}

